(0, 'custom_code', 'customJS', 'document.addEventListener(\"DOMContentLoaded\", function () {\n  function setFinalPrice() {\n    let finalPrice = 0;\n    let selectedOption = document.querySelector(\'.product-options input[type=\"radio\"]:checked, .product-options select\');\n    \n    if (selectedOption) {\n      let text = selectedOption.parentElement?.innerText || selectedOption.options?.[selectedOption.selectedIndex]?.textContent;\n      let match = text.match(/₹([\\d,]+)/);\n\n      if (match) {\n        finalPrice = parseFloat(match[1].replace(/,/g, \'\'));\n      }\n    }\n\n    // Update price display\n    document.querySelectorAll(\'.product-price .price-new, .price .price-new\').forEach(function (el) {\n      el.textContent = \'₹\' + finalPrice.toFixed(2);\n    });\n  }\n\n  // Bind event\n  document.querySelectorAll(\'.product-options input[type=\"radio\"], .product-options select\').forEach(function (el) {\n    el.addEventListener(\'change\', setFinalPrice);\n  });\n\n  // Trigger on load\n  setFinalPrice();\n});', 0),
